customCSS:
@import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@600;700&family=Inter:wght@400;500;600&family=JetBrains+Mono:wght@400;500&display=swap');

/* ===== Echosight Polish ===== */
body { font-family: 'Inter','Segoe UI',sans-serif !important; color: #e8e2d2 !important; }
.header h2 { font-family: 'Cinzel','Inter',serif !important; color: #f1d990 !important; font-weight: 700 !important; letter-spacing: 0.18em !important; text-transform: uppercase !important; font-size: 13px !important; text-shadow: 0 0 12px rgba(212,168,87,0.25), 0 1px 2px rgba(0,0,0,0.6) !important; }
.header h2 #shortcut-hint { letter-spacing: 0 !important; text-transform: none !important; font-family: 'Inter',sans-serif !important; color: rgba(184,176,154,0.62) !important; text-shadow: none !important; font-weight: 400 !important; }
.template-btn, .modal-btn.secondary { background: linear-gradient(180deg, rgba(20,40,46,0.9), rgba(10,18,22,0.95)) !important; color: #5fd8c8 !important; border: 1px solid rgba(95,216,200,0.45) !important; border-radius: 4px !important; font-family: 'Cinzel','Inter',sans-serif !important; font-weight: 600 !important; letter-spacing: 0.06em !important; transition: all .2s ease !important; }
.template-btn:hover, .modal-btn.secondary:hover { color: #f1d990 !important; border-color: rgba(212,168,87,0.6) !important; box-shadow: 0 0 14px rgba(212,168,87,0.18) !important; }
.add-btn, .modal-btn.primary { background: linear-gradient(180deg, rgba(45,38,18,0.58), rgba(28,22,10,0.74)) !important; color: #f1d990 !important; border: 1px solid rgba(212,168,87,0.55) !important; border-radius: 4px !important; font-family: 'Cinzel','Inter',sans-serif !important; font-weight: 600 !important; letter-spacing: 0.12em !important; text-transform: uppercase !important; box-shadow: inset 0 1px 0 rgba(212,168,87,0.12) !important; transition: all .2s ease !important; }
.add-btn:hover, .modal-btn.primary:hover { color: #fff2cf !important; border-color: rgba(212,168,87,0.86) !important; box-shadow: inset 0 1px 0 rgba(212,168,87,0.2), 0 0 14px rgba(212,168,87,0.25) !important; }
.task-input, .modal-input, .template-select, input[type='text'], textarea, select { background: rgba(7,6,13,0.7) !important; border: 1px solid rgba(212,168,87,0.18) !important; color: #e8e2d2 !important; border-radius: 4px !important; transition: border-color .2s, box-shadow .2s !important; }
.task-input:focus, .modal-input:focus, .template-select:focus, input[type='text']:focus, textarea:focus, select:focus { outline: 0 !important; border-color: rgba(95,216,200,0.6) !important; box-shadow: 0 0 0 2px rgba(95,216,200,0.12) !important; }
.progress-fill { background: linear-gradient(90deg, #2a8e84 0%, #5fd8c8 80%) !important; box-shadow: 0 0 12px rgba(95,216,200,0.5) !important; }
.progress-text { color: #b8b09a !important; font-family: 'JetBrains Mono','Inter',monospace !important; letter-spacing: 0.06em !important; }
.task-section-label { font-family: 'Cinzel','Inter',serif !important; color: #d4a857 !important; letter-spacing: 0.18em !important; text-transform: uppercase !important; font-size: 10px !important; border-bottom: 1px dashed rgba(212,168,87,0.18) !important; }
.task-item:hover { background: rgba(212,168,87,0.05) !important; }
.task-text { color: #e8e2d2 !important; }
.task-text.completed { color: #7a7363 !important; }
.task-delete { background: rgba(197,74,58,0.18) !important; color: #f0a896 !important; border: 1px solid rgba(197,74,58,0.35) !important; }
.task-delete:hover { background: rgba(227,128,74,0.4) !important; color: #ffe1d6 !important; border-color: rgba(227,128,74,0.7) !important; }

/* ===== Theme Modal ===== */
.modal { background: rgba(0,0,0,0.85) !important; backdrop-filter: blur(4px) !important; -webkit-backdrop-filter: blur(4px) !important; }
.modal-content { background: linear-gradient(180deg, rgba(20,17,31,0.98), rgba(11,9,18,0.98)) !important; border: 1px solid rgba(212,168,87,0.4) !important; border-radius: 8px !important; box-shadow: 0 24px 60px -10px rgba(0,0,0,0.85), 0 0 40px rgba(95,216,200,0.08) !important; position: relative !important; color: #e8e2d2 !important; }
.modal-content::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 1px; background: linear-gradient(90deg, transparent, rgba(212,168,87,0.5), transparent); pointer-events: none; }
.modal-title, .settings-title, .modal-content h4 { font-family: 'Cinzel','Inter',serif !important; color: #f1d990 !important; letter-spacing: 0.14em !important; text-transform: uppercase !important; font-weight: 700 !important; }
.app-dialog-message, .trigger-description, .community-template .description { color: #d8d1bf !important; }
.import-hint, .settings-help, .hotkey-help, .range-labels, .community-template .task-count { color: rgba(184,176,154,0.64) !important; }
.community-template { background: rgba(11,9,18,0.5) !important; border: 1px solid rgba(212,168,87,0.18) !important; border-radius: 6px !important; }
.modal-content-dialog.app-dialog-tone-danger { border-color: rgba(197,74,58,0.75) !important; }
.modal-content-dialog.app-dialog-tone-danger .modal-title { color: #f0a896 !important; }
.context-menu { background: linear-gradient(180deg, rgba(20,17,31,0.98), rgba(11,9,18,0.98)) !important; border: 1px solid rgba(212,168,87,0.4) !important; box-shadow: 0 12px 30px rgba(0,0,0,0.7), 0 0 0 1px rgba(0,0,0,0.4) !important; }
.context-menu div { color: #e8e2d2 !important; font-family: 'Inter',sans-serif !important; }
.context-menu div:hover { background: linear-gradient(90deg, rgba(212,168,87,0.18), rgba(212,168,87,0.06)) !important; color: #f1d990 !important; }
